120|fn parse_refactor_target_item(item: Value) -> Result<RefactorTarget, String> {
121|    let file_path = item
122|        .get("file_path")
123|        .and_then(Value::as_str)
124|        .ok_or_else(|| "each target must have file_path (string)".to_string())?;
125|
126|    let mut lines = Vec::new();
127|    if let Some(lines_value) = item.get("lines").and_then(Value::as_array) {
128|        for line in lines_value {
129|            lines.push(parse_line_number(line)?);
130|        }
131|    }
132|
133|    let mut ranges = Vec::new();
134|    if let Some(ranges_value) = item.get("ranges").and_then(Value::as_array) {
135|        for range in ranges_value {
136|            ranges.push(parse_target_range(range)?);
137|        }
138|    }
139|
140|    if lines.is_empty() && ranges.is_empty() {
141|        return Err("each target must list lines and/or ranges".to_string());
142|    }
143|
144|    Ok(RefactorTarget {
145|        file_path: resolve_workspace_path(file_path),
146|        lines,
147|        ranges,
148|    })
149|}
