151|fn parse_line_number(line: &Value) -> Result<usize, String> {
152|    let line_no = line
153|        .as_u64()
154|        .ok_or_else(|| "lines must contain only integers".to_string())?;
155|    if line_no == 0 {
156|        return Err("line numbers must be >= 1".to_string());
157|    }
158|    Ok(line_no as usize)
