161|fn parse_target_range(range: &Value) -> Result<TargetLineRange, String> {
162|    let start = range
163|        .get("start")
164|        .ok_or_else(|| "each range must have start".to_string())
165|        .and_then(parse_line_number)?;
166|    let end = range
167|        .get("end")
168|        .ok_or_else(|| "each range must have end".to_string())
169|        .and_then(parse_line_number)?;
170|    if end < start {
171|        return Err(format!("range end {end} must be >= start {start}"));
172|    }
173|    Ok(TargetLineRange { start, end })
