297|/// ponytail: Python call+construction scans can emit both line 11 and 11-22; keep the superset only
298|fn drop_subset_ranges(ranges: &mut Vec<LineRange>) {
299|    let snapshot = ranges.clone();
300|    ranges.retain(|small| {
301|        !snapshot.iter().any(|big| {
302|            big.start <= small.start
303|                && big.end >= small.end
304|                && (big.start < small.start || big.end > small.end)
305|        })
306|    });
307|}
