314|fn line_has_identifier(line: &str, ident: &str) -> bool {
315|    line.split(|c: char| !(c.is_ascii_alphanumeric() || c == '_'))
316|        .filter(|token| !token.is_empty())
317|        .any(|token| token == ident)
318|}
