320|fn expand_brace_range(lines: &[&str], start_idx: usize) -> LineRange {
321|    let mut depth = 0i32;
322|    let mut started = false;
323|    for (idx, line) in lines.iter().enumerate().skip(start_idx) {
324|        for ch in line.chars() {
325|            if ch == '{' {
326|                depth += 1;
327|                started = true;
328|            } else if ch == '}' {
329|                depth -= 1;
330|            }
331|        }
332|        if started && depth <= 0 {
333|            return LineRange {
334|                start: start_idx + 1,
335|                end: idx + 1,
336|            };
337|        }
338|    }
339|    LineRange {
340|        start: start_idx + 1,
341|        end: lines.len(),
342|    }
343|}
