410|fn load_type_schema(type_name: &str) -> Option<String> {
411|    use crate::cache::resolve_workspace_path;
412|
413|    let path = match type_name {
414|        "LogEvent" | "LogHeadline" | "LogMeta" => resolve_workspace_path("src/tools/log.rs"),
415|        "UiNotifyEvent" | "UiNotifyHeadline" | "UiNotifyMeta" | "emitUiNotify" => {
416|            resolve_workspace_path("frontend/src/modules/config-ui/types.ts")
417|        }
418|        "log_sort_event" | "SortEvent" | "SortHeadline" | "SortMeta" => {
419|            for basename in [
420|                "sort_log.py",
421|                "sort_log.zig",
422|                "sort_log.h",
423|                "sort_log.hpp",
424|                "sort_log.cpp",
425|                "sort_log.c",
426|            ] {
427|                if let Some(path) = find_workspace_file(basename) {
428|                    if let Some(schema) = load_schema_snippet(
429|                        &path,
430|                        &[
431|                            "pub const SortHeadline",
432|                            "typedef struct",
433|                            "struct SortHeadline",
434|                            "@dataclass",
435|                            "class SortHeadline",
436|                        ],
437|                    ) {
438|                        return Some(schema);
439|                    }
440|                }
441|            }
442|            return None;
443|        }
444|        "logSortEvent" | "sortdemo.SortEvent" => {
445|            for basename in ["SortLog.kt", "SortLog.java"] {
446|                if let Some(path) = find_workspace_file(basename) {
447|                    if let Some(schema) = load_schema_snippet(
448|                        &path,
449|                        &["object SortLog", "class SortLog", "final class SortLog"],
450|                    ) {
451|                        return Some(schema);
452|                    }
453|                }
454|            }
455|            return None;
456|        }
457|        _ => {
458|            let snake = type_name
459|                .chars()
460|                .enumerate()
461|                .flat_map(|(index, ch)| {
462|                    if ch.is_uppercase() && index > 0 {
463|                        vec!['_', ch.to_ascii_lowercase()]
464|                    } else {
465|                        vec![ch.to_ascii_lowercase()]
466|                    }
467|                })
468|                .collect::<String>();
469|            resolve_workspace_path(format!("src/tools/{snake}.rs"))
470|        }
471|    };
472|
473|    let content = std::fs::read_to_string(&path).ok()?;
474|    if type_name != "LogEvent"
475|        && type_name != "emitUiNotify"
476|        && type_name != "log_sort_event"
477|        && type_name != "logSortEvent"
478|        && !content.contains(&format!("struct {type_name}"))
479|        && !content.contains(&format!("pub struct {type_name}"))
480|        && !content.contains(&format!("interface {type_name}"))
481|        && !content.contains(&format!("class {type_name}"))
482|    {
483|        return None;
484|    }
485|
486|    let start = content
487|        .find("pub struct")
488|        .or_else(|| content.find("struct "))
489|        .or_else(|| content.find("export interface UiNotify"))
490|        .or_else(|| content.find("@dataclass"))
491|        .or_else(|| content.find("class "))
492|        .or_else(|| content.find("interface "))?;
493|    let end = content
494|        .find("pub fn ")
495|        .or_else(|| content.find("export function "))
496|        .or_else(|| content.find("/// ponytail"))
497|        .unwrap_or(content.len());
498|    Some(content[start..end].trim().to_string())
499|}
