220|                .filter(|f| f.is_finite() && *f >= 1.0)
221|                .map(|f| f as u64)
222|        }),
223|        Value::String(text) => text.parse::<u64>().ok(),
224|        _ => None,
225|    }
226|    .ok_or_else(|| format!("tool argument '{key}' must be a positive integer"))?;
227|    if n == 0 {
228|        return Err(format!("tool argument '{key}' must be >= 1"));
229|    }
230|    usize::try_from(n).map_err(|_| format!("tool argument '{key}' is too large"))
