259|    fn apply_codemod_to_targets(
260|        &self,
261|        context: &mut AgentContext,
262|        targets: &[RefactorTarget],
263|        transformation_rule: &str,
264|        method_name: Option<&str>,
265|    ) -> Result<Vec<PathBuf>, String> {
266|        let mut touched = Vec::new();
267|        let mut errors = Vec::new();
268|
269|        for target in targets {
270|            if !target.file_path.exists() {
271|                context.accumulated_data.push_str(&format!(
272|                    "Skipped missing file: {}\n",
273|                    target.file_path.display()
274|                ));
275|                continue;
276|            }
277|
278|            for range in &target.ranges {
279|                match self.apply_range_codemod(
280|                    context,
281|                    &target.file_path,
282|                    range.start,
283|                    range.end,
284|                    transformation_rule,
285|                    method_name,
286|                ) {
287|                    Ok(()) => {
288|                        if !touched.iter().any(|path| path == &target.file_path) {
289|                            touched.push(target.file_path.clone());
290|                            context.touched_files.push(target.file_path.clone());
291|                        }
292|                    }
293|                    Err(err) => {
294|                        errors.push(format!(
295|                            "{} lines {}-{}: {err}",
296|                            target.file_path.display(),
297|                            range.start,
298|                            range.end
299|                        ));
300|                        context
301|                            .accumulated_data
302|                            .push_str(&format!("Codemod error: {err}\n"));
303|                    }
304|                }
305|            }
306|
307|            for &line in &target.lines {
308|                match self.codemod_line(&target.file_path, line, transformation_rule) {
309|                    Ok(new_line) => {
310|                        let before = read_file_range(&target.file_path, line, line)?;
311|                        edit_file_line(&target.file_path, line, &new_line)?;
312|                        let changes = summarize_snippet_diff(&before, &new_line, line);
313|                        context.accumulated_data.push_str(&format!(
314|                            "Applied codemod to {} line {line}\n",
315|                            target.file_path.display()
316|                        ));
317|                        context.accumulated_data.push_str(&format_change_report(
318|                            &target.file_path,
319|                            line,
320|                            line,
321|                            &changes,
322|                            &new_line,
323|                        ));
324|                        if !touched.iter().any(|path| path == &target.file_path) {
325|                            touched.push(target.file_path.clone());
326|                            context.touched_files.push(target.file_path.clone());
327|                        }
328|                    }
329|                    Err(err) => {
330|                        errors.push(format!("{} line {line}: {err}", target.file_path.display()));
331|                        context
332|                            .accumulated_data
333|                            .push_str(&format!("Codemod error: {err}\n"));
334|                    }
335|                }
336|            }
337|        }
338|
339|        if touched.is_empty() {
340|            return Err(if errors.is_empty() {
341|                "no refactor targets were applied".to_string()
342|            } else {
343|                format!("all codemod attempts failed: {}", errors.join("; "))
344|            });
345|        }
346|
347|        Ok(touched)
348|    }
