350|    fn apply_range_codemod(
351|        &self,
352|        context: &mut AgentContext,
353|        path: &Path,
354|        start: usize,
355|        end: usize,
356|        transformation_rule: &str,
357|        method_name: Option<&str>,
358|    ) -> Result<(), String> {
359|        let snippet = read_file_range(path, start, end)?;
360|        let ext = path
361|            .extension()
362|            .and_then(|value| value.to_str())
363|            .unwrap_or_default();
364|        let new_content = match ext {
365|            "rs" => try_rust_struct_literal_codemod(&snippet, transformation_rule, path),
366|            "ts" | "tsx" => try_ts_object_literal_codemod(&snippet, transformation_rule, path),
367|            "py" => try_python_call_codemod(&snippet, transformation_rule, path),
368|            "java" | "kt" => try_java_call_codemod(&snippet, transformation_rule, path),
369|            "cpp" | "cc" | "cxx" | "hpp" | "c" | "h" | "zig" => {
370|                try_cpp_call_codemod(&snippet, transformation_rule, path)
371|            }
372|            _ => None,
373|        }
374|        .or_else(|| {
375|            self.codemod_range(path, start, end, transformation_rule, method_name)
376|                .ok()
377|        })
378|        .ok_or_else(|| "codemod produced no replacement".to_string())?;
379|        let changes = summarize_snippet_diff(&snippet, &new_content, start);
380|        edit_file_range(path, start, end, &new_content)?;
381|        context.accumulated_data.push_str(&format!(
382|            "Applied codemod to {} lines {}-{}\n",
383|            path.display(),
384|            start,
385|            end
386|        ));
387|        context.accumulated_data.push_str(&format_change_report(
388|            path, start, end, &changes, &new_content,
389|        ));
390|        Ok(())
391|    }
