393|    fn codemod_content(&self, user_message: &str, single_line: bool) -> Result<String, String> {
394|        let empty_tools = LlmToolSet::new();
395|        let request = LlmRequest::new(TRANSFORMER_CODEMOD_SYSTEM_PROMPT, user_message, &empty_tools);
396|        let turn = self.codemod_client.complete(request)?;
397|        let content = turn
398|            .content
399|            .map(|text| text.trim().to_string())
400|            .filter(|text| !text.is_empty())
401|            .ok_or_else(|| "codemod model returned empty content".to_string())?;
402|        if single_line {
403|            Ok(content.lines().next().unwrap_or(&content).to_string())
404|        } else {
405|            Ok(content)
406|        }
407|    }
