501|// ponytail: shallow basename walk; upgrade to ripgrep if schema files proliferate
502|const SCHEMA_SKIP_DIRS: &[&str] = &["target", "node_modules", ".git", "dist"];
503|
504|fn find_workspace_file(basename: &str) -> Option<PathBuf> {
505|    use crate::cache::mcp_workspace_root;
506|    find_file_by_basename(&mcp_workspace_root(), basename, 14)
507|}
508|
509|fn find_file_by_basename(dir: &Path, basename: &str, depth: usize) -> Option<PathBuf> {
510|    if depth == 0 {
511|        return None;
512|    }
513|    let entries = std::fs::read_dir(dir).ok()?;
514|    for entry in entries.flatten() {
515|        let path = entry.path();
516|        let file_name = entry.file_name();
517|        let name = file_name.to_string_lossy();
518|        if path.is_dir() {
519|            if SCHEMA_SKIP_DIRS.contains(&name.as_ref()) {
520|                continue;
521|            }
522|            if let Some(found) = find_file_by_basename(&path, basename, depth - 1) {
523|                return Some(found);
524|            }
525|        } else if name == basename {
526|            return Some(path);
527|        }
528|    }
529|    None
530|}
531|
532|fn load_schema_snippet(path: &Path, start_markers: &[&str]) -> Option<String> {
533|    let content = std::fs::read_to_string(path).ok()?;
534|    let start = start_markers
535|        .iter()
536|        .find_map(|marker| content.find(marker))?;
537|    Some(content[start..].trim().to_string())
538|}
