576|        }
577|
578|        let thought = model_turn.content.as_deref().unwrap_or("").to_string();
579|        if !thought.is_empty() {
580|            context
581|                .accumulated_data
582|                .push_str(&format!("Thought:\n{thought}\n"));
583|        }
584|
585|        for tool_call in &model_turn.tool_calls {
586|            context.accumulated_data.push_str(&format!(
587|                "Tool: {}({})\n",
588|                tool_call.name, tool_call.arguments
589|            ));
590|
591|            match tool_call.name.as_str() {
592|                "gather_refactor_targets" => {
593|                    let method_name = parse_method_name(&tool_call.arguments)?;
594|                    match find_refactor_targets(&method_name) {
595|                        Ok(mut targets) if !targets.is_empty() => {
596|                            if let Some(scope) = &self.scope_path {
597|                                let total = targets.len();
598|                                targets = filter_targets_by_scope(targets, scope);
599|                                if targets.is_empty() {
600|                                    return Err(format!(
601|                                        "no refactor targets under scope {}",
602|                                        scope.display()
603|                                    ));
604|                                }
605|                                context.accumulated_data.push_str(&format!(
606|                                    "\n[SYSTEM]: Scoped gather to {} ({}/{} targets)\n",
607|                                    scope.display(),
608|                                    targets.len(),
609|                                    total
610|                                ));
611|                            }
612|                            context.accumulated_data.push_str(
613|                                "\n[SYSTEM]: Deterministic refactor target scan succeeded\n",
614|                            );
615|                            let output = format_refactor_targets_block(&targets);
616|                            context
617|                                .accumulated_data
618|                                .push_str(&format!("Observation:\n{output}\n"));
619|                            let rule = extract_refactor_instruction(&context.input_prompt);
620|                            self.apply_and_triage(
621|                                context,
622|                                &targets,
623|                                &rule,
624|                                Some(&method_name),
625|                            )
626|                            .await?;
627|                        }
628|                        _ => {
629|                            let output =
630|                                self.run_scout_subagent(context, &method_name).await?;
631|                            context
632|                                .accumulated_data
633|                                .push_str(&format!("Observation:\n{output}\n"));
634|                        }
635|                    }
636|                }
637|                "apply_structural_codemod" => {
638|                    let (transformation_rule, targets) =
639|                        parse_apply_structural_codemod_arguments(&tool_call.arguments)?;
640|                    self.apply_and_triage(
641|                        context,
642|                        &targets,
643|                        &transformation_rule,
644|                        None,
645|                    )
646|                    .await?;
